solution: ```class Solution {
public:
    int maxLengthBetweenEqualCharacters(string s) {
        int first[26];
        fill(first, first + 26, -1);
        int maxLen = -1;
        for (int i = 0; i < s.size(); ++i) {
            int c = s[i] - 'a';
            if (first[c] == -1) {
                first[c] = i;
            } else {
                maxLen = max(maxLen, i - first[c] - 1);
            }
        }
        return maxLen;
    }
};
```
